"const fs = require('fs');
const readline = require('readline');

const backupPath = 'app_tsx_step_1460.txt';
const targetPath = 'src/App.tsx';

const rl = readline.createInterface({
  input: fs.createReadStream(backupPath),
  crlfDelay: Infinity
});

const cleanLines = [];

rl.on('line', (line) => {
  // Matches "  8: 1: import" or "1: import"
  // Let's strip any leading spaces, look for the colon that separates line number, and get the rest.
  const match = line.match(/^\d+:\s*(.*)$/);
  if (match) {
    cleanLines.push(match[1]);
  }
});

rl.on('close', () => {
  // Let's check if the first line starts with a number like "1: "
  // If so, we need to strip "1: ", "2: ", etc.
  const finalCode = cleanLines.map(line => {
    const codeMatch = line.match(/^\d+:\s*(.*)$/);
    return codeMatch ? codeMatch[1] : line;
  }).join('\n');

  fs.writeFileSync(targetPath, finalCode);
  console.log(`Successfully restored ${targetPath} from backup!`);
});
"
